import { getContract, getContractReadOnly } from './contract';

/**
 * Listen to RoomCreated events
 */
export const listenToRoomCreated = async (callback) => {
  try {
    const contract = await getContractReadOnly();
    
    contract.on('RoomCreated', (roomId, name, creator, isNFTGated, nftContract, event) => {
      console.log('🎉 New room created:', {
        roomId: roomId.toString(),
        name,
        creator,
        isNFTGated,
        nftContract,
        blockNumber: event.log.blockNumber,
      });
      
      if (callback) {
        callback({
          roomId: roomId.toString(),
          name,
          creator,
          isNFTGated,
          nftContract,
        });
      }
    });
    
    console.log('👂 Listening to RoomCreated events');
  } catch (error) {
    console.error('Failed to listen to RoomCreated events:', error);
  }
};

